"""Вкладка «Сравнение»: столбчатый график метрики по фильтрам.Canvas заполняет всю вкладку. Столбцы фиксированной толщины (_BAR_WIDTH).Ось X ограничена, чтобы столбцы не растягивались при малом числе фильтров."""from __future__ import annotationsimport mathimport numpy as npfrom matplotlib.backends.backend_qtagg import (    FigureCanvasQTAgg as FigureCanvas,    NavigationToolbar2QT as NavigationToolbar,)from matplotlib.figure import Figurefrom PySide6.QtWidgets import (    QComboBox, QHBoxLayout, QLabel, QSizePolicy, QVBoxLayout, QWidget,)from ...core.types import ExperimentSeries_METRICS: dict[str, tuple[str, str]] = {    "MSE":                 ("mse", ""),    "RMSE":                ("rmse", ""),    "SNR до, дБ":          ("snr_before_db", " (дБ)"),    "SNR после, дБ":       ("snr_after_db", " (дБ)"),    "Улучшение SNR, дБ":   ("snr_improvement_db", " (дБ)"),    "Корреляция":          ("correlation", ""),}_BAR_WIDTH = 0.45# Максимальная доля ширины figure, которую занимают оси._MAX_AXES_WIDTH_FRAC: dict[int, float] = {    1: 0.30,    2: 0.45,    3: 0.60,    4: 0.72,    5: 0.80,    6: 0.88,}class ComparisonTab(QWidget):    def __init__(self, parent: QWidget | None = None) -> None:        super().__init__(parent)        self._metric_combo = QComboBox()        self._metric_combo.addItems(list(_METRICS.keys()))        self._metric_combo.setCurrentText("Улучшение SNR, дБ")        self._metric_combo.currentIndexChanged.connect(self._redraw)        self._figure = Figure()        self._canvas = FigureCanvas(self._figure)        self._canvas.setSizePolicy(QSizePolicy.Expanding, QSizePolicy.Expanding)        self._toolbar = NavigationToolbar(self._canvas, self)        top = QHBoxLayout()        top.addWidget(QLabel("Метрика:"))        top.addWidget(self._metric_combo)        top.addStretch(1)        lay = QVBoxLayout(self)        lay.setContentsMargins(0, 0, 0, 0)        lay.setSpacing(0)        lay.addLayout(top)        lay.addWidget(self._toolbar)        lay.addWidget(self._canvas, 1)        self._series: ExperimentSeries | None = None        self._init_placeholder()    # ---------- API ----------------------------------------------------------    def display_series(self, series: ExperimentSeries) -> None:        self._series = series        self._redraw()    def clear(self) -> None:        self._series = None        self._init_placeholder()    # ---------- рендер -------------------------------------------------------    def _init_placeholder(self) -> None:        self._figure.clear()        ax = self._figure.add_subplot(1, 1, 1)        ax.set_title("Сравнение фильтров (выполните серию экспериментов)",                      fontsize=10)        ax.grid(True, alpha=0.3)        self._canvas.draw_idle()    def _redraw(self) -> None:        s = self._series        if s is None or not s.filter_names:            self._init_placeholder()            return        metric_label = self._metric_combo.currentText()        field_base, unit_suffix = _METRICS[metric_label]        names = list(s.filter_names)        n = len(names)        means: list[float] = []        stds: list[float] = []        for fname in names:            a = s.aggregates[fname]            m = float(getattr(a, f"{field_base}_mean"))            sd = float(getattr(a, f"{field_base}_std"))            if not math.isfinite(m):                m = math.nan            if not math.isfinite(sd):                sd = 0.0            means.append(m)            stds.append(sd)        self._figure.clear()        ax = self._figure.add_subplot(1, 1, 1)        x = np.arange(n, dtype=np.float64)        yerr = stds if s.n_trials > 1 else None        bars = ax.bar(            x, means,            width=_BAR_WIDTH,            yerr=yerr, capsize=4,            color="tab:blue", alpha=0.8, edgecolor="black", linewidth=0.8,        )        ax.set_xticks(x)        wrapped = [_wrap_label(nm) for nm in names]        ax.set_xticklabels(wrapped, fontsize=8)        ax.set_ylabel(f"{metric_label}{unit_suffix}", fontsize=9)        ax.set_title(f"{metric_label} по фильтрам (n = {s.n_trials})",                      fontsize=10)        ax.grid(True, axis="y", alpha=0.3)        ax.set_xlim(-0.6, max(n - 0.4, 0.6))        for rect, value in zip(bars, means):            if not math.isfinite(value):                continue            ax.annotate(                f"{value:.3g}",                xy=(rect.get_x() + rect.get_width() / 2, value),                xytext=(0, 4), textcoords="offset points",                ha="center", va="bottom", fontsize=8,            )        # Ограничить ширину осей — столбцы не растягиваются на весь экран.        frac = _MAX_AXES_WIDTH_FRAC.get(n, 0.92)        side = (1.0 - frac) / 2.0        self._figure.subplots_adjust(            left=max(side, 0.06),            right=min(1.0 - side, 0.96),            top=0.90,            bottom=0.15,        )        self._canvas.draw_idle()    # ---------- internals ---------------------------------------------------def _wrap_label(name: str, width: int = 14) -> str:    words = name.split()    lines: list[str] = []    cur = ""    for w in words:        candidate = (cur + " " + w).strip()        if len(candidate) > width and cur:            lines.append(cur)            cur = w        else:            cur = candidate    if cur:        lines.append(cur)    return "\n".join(lines)